import React, { useState } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { decrementActionCreator, incrementActionCreator } from '../reducers/counterReducer';

function Counter() {
    const [jump,setJump]=useState(1)
    const state = useSelector(state=>state.count)
    const {count} = state;
    const dispatch = useDispatch()
  return (
    <>
     <h1>Count - {count}</h1>
     <input type="text" min={1} max={10} onChange={e=>setJump(+e.target.value)} />
     <button onClick={()=>dispatch(decrementActionCreator(jump))}>-</button> 
     <button onClick={()=>dispatch(incrementActionCreator(jump))}>+</button> 
    </>
  )
}

export default Counter
